 function opportunitySummary(state,opp,m){const alerts=[];if(!m.next)alerts.push('Aucune prochaine action planifiée.');if(m.invoices.some(x=>effectiveDocumentStatus(state,x)==='overdue'))alerts.push('Une facture liée est en retard.');if(opp.expected_close_date&&opp.expected_close_date<today())alerts.push('La date de clôture prévue est dépassée.');return`<div class="commercial-detail-grid"><section class="phase1-card commercial-financial-grid">${[['Montant estimé',m.estimated],['Montant proposé',m.proposed],['Montant accepté',m.accepted],['Total facturé',m.invoiced],['Total encaissé',m.collected],['Reste à encaisser',m.remaining],['Avoirs',m.creditTotal],['Marge réalisée',m.marginRealized]].map(([label,value])=>`<div><span>${esc(label)}</span><b>${money(value)}</b></div>`).join('')}</section><section class="phase1-card"><h2>Progression commerciale</h2><div class="commercial-progress"><i style="width:${Math.max(0,Math.min(100,Number(opp.probability)||0))}%"></i></div><p>${Number(opp.probability)||0} % · ${money(m.weighted)} pondéré · ${m.daysInStage} jour(s) dans l’étape</p></section><section class="phase1-card"><h2>Prochaine action</h2>${m.next?`<button class="commercial-row-action" onclick="PilozCommercialWorkspace.openActivity('${opp.id}','','${m.next.id}')"><b>${esc(m.next.subject)}</b><small>${datetime(m.next.due_at||m.next.scheduled_at)}</small></button>`:'<p>Aucune prochaine action.</p>'}${button('Ajouter une activité',`PilozCommercialWorkspace.openActivity('${opp.id}')`,'btn-ghost')}</section><section class="phase1-card"><h2>Alertes</h2>${alerts.map(x=>`<p class="commercial-alert">${esc(x)}</p>`).join('')||'<p>Aucune alerte commerciale.</p>'}</section></div>`;}
 function documentTable(rows){const state=s();return rows.length?`<div class="modern-table-shell"><table class="modern-table"><thead><tr><th>Numéro</th><th>Type</th><th>Date</th><th>Statut</th><th>HT</th><th>TTC</th></tr></thead><tbody>${rows.map(row=>{const effective=effectiveDocumentStatus(state,row),meta=documentStatuses()?.statusMeta?.(effective);return`<tr onclick="PilozApp.editDocument('${row.id}')"><td><b>${esc(row.number||'Brouillon')}</b></td><td>${esc(docTypes[row.document_type]||row.document_type)}</td><td>${date(row.issue_date)}</td><td>${status(meta?.label||pipelineStatusLabel(effective),meta?.tone||'info')}</td><td>${money(row.total_excl_tax)}</td><td>${money(row.total_incl_tax)}</td></tr>`;}).join('')}</tbody></table></div>`:empty('Aucun document lié','Créez ou rattachez un document à cette opportunité.');}
